import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Use nextLine() to read the whole line

        int maxLength = 10; // Define maximum length for buffer

        if (input.length() <= maxLength) {
            char[] buffer = new char[maxLength];
            input.getChars(0, Math.min(input.length(), maxLength), buffer, 0); // Ensure not to exceed buffer length
            System.out.println("Buffer content: " + new String(buffer));
        } else {
            System.out.println("Input string is too long!");
        }
    }
}

